def harish_chandra_module(lie_group):
    '''
    Representation of a real Lie group with regularity and finiteness conditions.
    Named after Harish-Chandra (mathematician & physicist).
    '''
    if not isinstance(lie_group, RealLieGroup):
        raise TypeError('Expected a real Lie group instance.')
    return Representation(lie_group, regular=True, finite=True)
